  1→/**
  2→ * Database resource library functions
  3→ * Wrappers for MySQL and Redis database operations
  4→ */
  5→
  6→import { MittwaldAPIV2Client } from '@mittwald/api-client';
  7→import { assertStatus } from '@mittwald/api-client-commons';
  8→import type { LibraryFunctionBase, LibraryResult } from '../contracts/functions.js';
  9→import { LibraryError } from '../contracts/functions.js';
 10→
 11→// ============================================================================
 12→// MYSQL DATABASES
 13→// ============================================================================
 14→
 15→export interface ListMysqlDatabasesOptions extends LibraryFunctionBase {
 16→  projectId: string;
 17→}
 18→
 19→export async function listMysqlDatabases(options: ListMysqlDatabasesOptions): Promise<LibraryResult<any[]>> {
 20→  const startTime = performance.now();
 21→
 22→  try {
 23→    const client = MittwaldAPIV2Client.newWithToken(options.apiToken);
 24→    const response = await client.database.listMysqlDatabases({ projectId: options.projectId });
 25→    assertStatus(response, 200);
 26→
 27→    return { data: response.data, status: response.status, durationMs: performance.now() - startTime };
 28→  } catch (error) {
 29→    throw new LibraryError(
 30→      error instanceof Error ? error.message : 'Unknown error',
 31→      (error as any).status || 500,
 32→      { originalError: error, durationMs: performance.now() - startTime }
 33→    );
 34→  }
 35→}
 36→
 37→export interface GetMysqlDatabaseOptions extends LibraryFunctionBase {
 38→  databaseId: string;
 39→}
 40→
 41→export async function getMysqlDatabase(options: GetMysqlDatabaseOptions): Promise<LibraryResult<any>> {
 42→  const startTime = performance.now();
 43→
 44→  try {
 45→    const client = MittwaldAPIV2Client.newWithToken(options.apiToken);
 46→    const response = await client.database.getMysqlDatabase({ mysqlDatabaseId: options.databaseId });
 47→    assertStatus(response, 200);
 48→
 49→    return { data: response.data, status: response.status, durationMs: performance.now() - startTime };
 50→  } catch (error) {
 51→    throw new LibraryError(
 52→      error instanceof Error ? error.message : 'Unknown error',
 53→      (error as any).status || 500,
 54→      { originalError: error, durationMs: performance.now() - startTime }
 55→    );
 56→  }
 57→}
 58→
 59→export interface CreateMysqlDatabaseOptions extends LibraryFunctionBase {
 60→  projectId: string;
 61→  description: string;
 62→  version: string;
 63→  characterSettings?: any;
 64→}
 65→
 66→export async function createMysqlDatabase(options: CreateMysqlDatabaseOptions): Promise<LibraryResult<any>> {
 67→  const startTime = performance.now();
 68→
 69→  try {
 70→    const client = MittwaldAPIV2Client.newWithToken(options.apiToken);
 71→
 72→    const data: any = {
 73→      description: options.description,
 74→      version: options.version,
 75→    };
 76→    if (options.characterSettings) data.characterSettings = options.characterSettings;
 77→
 78→    const response = await client.database.createMysqlDatabase({
 79→      projectId: options.projectId,
 80→      data,
 81→    });
 82→    assertStatus(response, 201);
 83→
 84→    return { data: response.data, status: response.status, durationMs: performance.now() - startTime };
 85→  } catch (error) {
 86→    throw new LibraryError(
 87→      error instanceof Error ? error.message : 'Unknown error',
 88→      (error as any).status || 500,
 89→      { originalError: error, durationMs: performance.now() - startTime }
 90→    );
 91→  }
 92→}
 93→
 94→export interface DeleteMysqlDatabaseOptions extends LibraryFunctionBase {
 95→  databaseId: string;
 96→}
 97→
 98→export async function deleteMysqlDatabase(options: DeleteMysqlDatabaseOptions): Promise<LibraryResult<void>> {
 99→  const startTime = performance.now();
100→
101→  try {
102→    const client = MittwaldAPIV2Client.newWithToken(options.apiToken);
103→    const response = await client.database.deleteMysqlDatabase({ mysqlDatabaseId: options.databaseId });
104→    assertStatus(response, 204);
