  userId: string;
  description?: string;
  password?: string;
}

export async function updateMysqlUser(options: UpdateMysqlUserOptions): Promise<LibraryResult<void>> {
  const startTime = performance.now();

  try {
    const client = MittwaldAPIV2Client.newWithToken(options.apiToken);

